export const ANNEX_INDEX = [{"id":1,"number":"I","title":"List of Union Harmonisation Legislation","summary":"Identifies existing EU harmonisation legislation that intersects with the AI Act. If an AI system is a safety component of, or is itself, a product covered by this legislation, the high-risk classification under Article 6(1) applies."},{"id":2,"number":"II","title":"List of Criminal Offences Referred to in Article 5(1), First Subparagraph, Point (h)(iii)","summary":"Defines the scope of serious criminal offences for which certain real-time remote biometric identification systems may be permitted, subject to strict conditions under Article 5."},{"id":3,"number":"III","title":"High-Risk AI Systems Referred to in Article 6(2)","summary":"Provides the standalone classification of high-risk AI systems, independent of product safety legislation. These are systems whose use in these eight areas poses significant risks to fundamental rights, health, or safety."},{"id":4,"number":"IV","title":"Technical Documentation Referred to in Article 11(1)","summary":"Defines the minimum content required for the technical documentation of high-risk AI systems. Must be drawn up before the system is placed on the market or put into service and kept up to date."},{"id":5,"number":"V","title":"EU Declaration of Conformity","summary":"Specifies the mandatory content of the EU Declaration of Conformity referenced in Article 47, which is the formal statement by a provider that a high-risk AI system meets regulatory requirements."},{"id":6,"number":"VI","title":"Conformity Assessment Procedure Based on Internal Control","summary":"Defines the self-assessment route for providers of high-risk AI systems that do not require third-party (notified body) involvement. This is the simpler of the two conformity assessment paths."},{"id":7,"number":"VII","title":"Conformity Based on an Assessment of the Quality Management System and an Assessment of the Technical Documentation","summary":"Defines the conformity assessment route involving a notified body that evaluates both the provider's quality management system and the technical documentation for each AI system. This is the more rigorous conformity path, required for certain high-risk AI systems (particularly those in Annex III areas 1, 6, 7, and 8)."},{"id":8,"number":"VIII","title":"Information to be Submitted upon the Registration of High-Risk AI Systems in Accordance with Article 49","summary":"Specifies what information providers and deployers must submit to the EU database for high-risk AI systems. Divided into three sections covering provider information, non-high-risk designation information, and deployer information."},{"id":9,"number":"IX","title":"Information to be Submitted upon the Registration of High-Risk AI Systems Listed in Annex III in Relation to Testing in Real World Conditions in Accordance with Article 60","summary":"Specifies information required when registering high-risk AI systems listed in Annex III that are undergoing real-world testing conditions, ensuring transparency and traceability for experimental deployments."},{"id":10,"number":"X","title":"Union Legislative Acts on Large-Scale IT Systems in the Area of Freedom, Security and Justice","summary":"Lists the EU legislative acts governing the major EU-wide information technology systems in the justice and security domain. AI systems that are components of these IT systems are classified as high-risk under Article 6(2) when listed in Annex III."},{"id":11,"number":"XI","title":"Technical Documentation Referred to in Article 53(1), Point (a) — Technical Documentation for Providers of General-Purpose AI Models","summary":"Specifies the technical documentation that providers of general-purpose AI (GPAI) models must draw up and make available to the AI Office and national competent authorities."},{"id":12,"number":"XII","title":"Transparency Information Referred to in Article 53(1), Point (b) — Technical Documentation for Providers of General-Purpose AI Models to Downstream Providers that Integrate the Model into Their AI System","summary":"Specifies what technical documentation GPAI model providers must share with downstream providers who integrate the model into their own AI systems, to enable understanding, compliance, and proper integration."},{"id":13,"number":"XIII","title":"Criteria for the Designation of General-Purpose AI Models with Systemic Risk Referred to in Article 51","summary":"Establishes the criteria the Commission uses, complementing the computational threshold of 10^25 FLOPs set in Article 51(2), to determine whether a GPAI model presents systemic risk."}];
